console.log('AXcent Dance website initialized.');document.addEventListener('DOMContentLoaded',()=>{const mobileMenuBtn=document.querySelector('.mobile-menu-btn'),navLinks=document.querySelector('.nav-links');if(mobileMenuBtn&&navLinks){mobileMenuBtn.addEventListener('click',(e)=>{e.preventDefault();navLinks.classList.toggle('active');mobileMenuBtn.classList.toggle('active')})}document.querySelectorAll('.nav-links a').forEach(link=>{link.addEventListener('click',()=>{if(navLinks)navLinks.classList.remove('active');if(mobileMenuBtn)mobileMenuBtn.classList.remove('active')})});document.querySelectorAll('.dropbtn').forEach(btn=>{btn.addEventListener('click',(e)=>{if(window.innerWidth<900){e.preventDefault();btn.closest('.dropdown').classList.toggle('active')}})});const header=document.querySelector('.main-header');window.addEventListener('scroll',()=>{if(window.scrollY>50){header.classList.add('scrolled')}else{header.classList.remove('scrolled')}});const revealObserver=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('active')}})},{threshold:0.1,rootMargin:"0px 0px -50px 0px"});document.querySelectorAll('.reveal').forEach(el=>revealObserver.observe(el));document.addEventListener('click',(e)=>{const item=e.target.closest('.value-item');if(item){const isActive=item.classList.contains('active');document.querySelectorAll('.value-item').forEach(i=>i.classList.remove('active'));if(!isActive)item.classList.add('active')}});const path=window.location.pathname,cleanPath=path.length>1&&path.endsWith('/')?path.slice(0,-1):path;let page=cleanPath.split('/').pop()||'index.html';if(page.endsWith('.html'))page=page.slice(0,-5);if(page==='index')page='';document.querySelectorAll('.nav-links a').forEach(link=>{let href=link.getAttribute('href');if(!href)return;href=href.replace('./','');if(href.endsWith('.html'))href=href.slice(0,-5);if(href==='index'||href==='')href='';if(href===page)link.classList.add('active')});});const trialForm=document.getElementById('trialForm');if(trialForm){trialForm.addEventListener('submit',e=>{e.preventDefault();const btn=document.getElementById('submitTrialBtn'),orig=btn.innerHTML;btn.innerHTML='<span>Submitting...</span>';btn.disabled=true;const fd=new FormData(trialForm),data={firstname:fd.get('firstname'),lastname:fd.get('lastname'),phone:fd.get('phone'),email:fd.get('email'),selected_class:fd.get('class-select')};const scriptURL='https://script.google.com/macros/s/AKfycbwPqLutAq-xa9OkSiT-rLm72DJCdQ2Xw10Yp4DvHexTq42HxCKJyJr8mJmZ0RuZSc7A5A/exec',formSubmitURL='https://formsubmit.co/ajax/info@axcentdance.com';const fsData={_subject:`New Trial Booking from ${data.firstname} ${data.lastname}`,_template:'table',_captcha:'false',firstname:data.firstname,lastname:data.lastname,phone:data.phone,email:data.email,class:data.selected_class};const p1=fetch(scriptURL,{method:'POST',body:JSON.stringify(data),mode:'no-cors'}),p2=fetch(formSubmitURL,{method:'POST',headers:{'Content-Type':'application/json','Accept':'application/json'},body:JSON.stringify(fsData)});Promise.allSettled([p1,p2]).then(()=>{window.location.href='thank-you-trial.html'}).catch(()=>{btn.innerHTML=orig;btn.disabled=false})})};